mapper.select:
SELECT B.SITE_CD AS siteCd , B.BRD_ID AS brdId , B.BRD_SE AS brdSe , B.BRD_NM AS brdNm , B.BRD_DESC AS brdDesc , B.ORD AS ord , B.USE_YN AS useYn , B.LGN_USER_USE_YN AS lgnUserUseYn , B.WRTR_PSN_QRY_YN AS wrtrPsnQryYn , B.PWD_USE_YN AS pwdUseYn , B.FILE_USE_YN AS fileUseYn , B.CMT_USE_YN AS cmtUseYn , A.WRT_AUTH_CD AS wrtAuthCd , A.QRY_AUTH_CD AS qryAuthCd , A.CMT_AUTH_CD AS cmtAuthCd , TO_CHAR(B.CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(B.UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_BRD B LEFT JOIN CMS_BRD_AUTH A ON A.BRD_ID = B.BRD_ID AND A.SITE_CD = B.SITE_CD WHERE B.SITE_CD = #{siteCd}
AND B.BRD_SE = #{brdSe}
ORDER BY B.ORD ASC, B.BRD_ID ASC

mapper.update:
UPDATE CMS_BRD
   SET BRD_NM          = #{vo.brdNm}
     , BRD_DESC        = #{vo.brdDesc}
     , ORD             = #{vo.ord}
     , USE_YN          = NVL(#{vo.useYn}, USE_YN)
     , LGN_USER_USE_YN = NVL(#{vo.lgnUserUseYn}, LGN_USER_USE_YN)
     , WRTR_PSN_QRY_YN = NVL(#{vo.wrtrPsnQryYn}, WRTR_PSN_QRY_YN)
     , PWD_USE_YN      = NVL(#{vo.pwdUseYn}, PWD_USE_YN)
     , FILE_USE_YN     = NVL(#{vo.fileUseYn}, FILE_USE_YN)
     , CMT_USE_YN      = NVL(#{vo.cmtUseYn}, CMT_USE_YN)
     , 
 WHERE SITE_CD         = #{siteCd}
   AND BRD_ID          = #{brdId}

mapper.delete:
DELETE FROM CMS_BRD
 WHERE SITE_CD = #{siteCd}
   AND BRD_ID  = #{brdId}

